232	\begin{lemma}\leanok
233	[Stage 1 --- smooth implies flat at every stalk]
234	  \label{lem:stalkMap_flat_of_smooth}
235	  \lean{AlgebraicGeometry.Scheme.stalkMap_flat_of_smooth}
236	  Let \(X \to \Spec(\bar k)\) be a smooth morphism over an algebraically closed
237	  field \(\bar k\). Then for every point \(z \in X\) the induced ring map on
238	  stalks is flat.
239	\end{lemma}
240	
241	\begin{proof}
242	  Proved directly in Lean: the smooth-implies-flat instance composed with the
243	  stalk-map flatness characterisation. A sub-step of
244	  \cref{lem:smooth_to_regular_local_ring}.
245	\end{proof}
