247	\begin{lemma}\leanok
248	[Stage 2 --- smooth implies a standard-smooth presentation at a point]
249	  \label{lem:exists_standardSmooth_at_of_smooth}
250	  \lean{AlgebraicGeometry.Scheme.exists_isStandardSmooth_at_of_smooth}
251	  For a smooth morphism \(X \to \Spec(\bar k)\) and a point \(z \in X\), there
252	  exist affine open neighbourhoods \(U \subseteq \Spec(\bar k)\) and \(V \ni z\)
253	  in \(X\) with \(V \subseteq X^{-1}(U)\) such that the induced ring map
254	  \(\Gamma(\Spec \bar k, U) \to \Gamma(X, V)\) is standard smooth (Stacks 00T7).
255	\end{lemma}
256	
257	\begin{proof}
258	  Proved directly in Lean: re-export of the scheme-level Stacks 00T7 packaging.
259	  A sub-step of \cref{lem:exists_algebra_standardSmooth_stalk_localization}.
260	\end{proof}
